--
-- Table structure for table `t041t_currencies`
--

DROP TABLE IF EXISTS `t041t_currencies`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `t041t_currencies` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'Consecutivo único del registro',
  `code` varchar(8) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Código ISO 4217 de la moneda. Ej: COP, USD, EUR',
  `name_english_short` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Nombre corto de la moneda en inglés. Ej: Peso',
  `name_english_full` varchar(256) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Nombre completo de la moneda en inglés. Ej: Colombian Peso',
  `decimal_digits` int NOT NULL DEFAULT '2' COMMENT 'Número de decimales estándar. Ej: 2 para USD, 0 para JPY',
  `symbol` varchar(8) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Símbolo visual de la moneda. Ej: $, €, £',
  `thousands_separator` varchar(2) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Separador de miles. Ej: , o .',
  `decimal_separator` varchar(2) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Separador de decimales. Ej: . o ,',
  `symbol_position` varchar(16) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Posición del símbolo respecto al valor: IZQUIERDA o DERECHA',
  `status` int NOT NULL DEFAULT '1' COMMENT 'Estado del registro: 1 activo, 0 inactivo',
  `created_at` datetime(6) NOT NULL COMMENT 'Fecha y hora de creación del registro',
  `updated_at` datetime(6) NOT NULL COMMENT 'Fecha y hora de última actualización del registro',
  `created_by` int NOT NULL COMMENT 'Usuario que creó el registro',
  `updated_by` int NOT NULL COMMENT 'Usuario que realizó la última actualización del registro',
  PRIMARY KEY (`id`),
  UNIQUE KEY `UK_t041t_code` (`code`),
  CONSTRAINT `CHK_GT0_t041t_decimal_digits` CHECK ((`decimal_digits` >= 0)),
  CONSTRAINT `CHK_NE_t041t_code` CHECK ((`code` <> _utf8mb4'')),
  CONSTRAINT `CHK_NE_t041t_decimal_separator` CHECK ((`decimal_separator` <> _utf8mb4'')),
  CONSTRAINT `CHK_NE_t041t_name_english_full` CHECK ((`name_english_full` <> _utf8mb4'')),
  CONSTRAINT `CHK_NE_t041t_name_english_short` CHECK ((`name_english_short` <> _utf8mb4'')),
  CONSTRAINT `CHK_NE_t041t_symbol` CHECK ((`symbol` <> _utf8mb4'')),
  CONSTRAINT `CHK_NE_t041t_symbol_position` CHECK ((`symbol_position` <> _utf8mb4'')),
  CONSTRAINT `CHK_NE_t041t_thousands_separator` CHECK ((`thousands_separator` <> _utf8mb4''))
) ENGINE=InnoDB AUTO_INCREMENT=181 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Catálogo de monedas. Estándar ISO 4217. Fuente: codesall.csv';
/*!40101 SET character_set_client = @saved_cs_client */;

