--
-- Table structure for table `t042t_currency_translations`
--

DROP TABLE IF EXISTS `t042t_currency_translations`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `t042t_currency_translations` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'Consecutivo único del registro',
  `id_currency` int NOT NULL COMMENT 'Referencia al id de la moneda en t041t_currencies',
  `id_language` int NOT NULL COMMENT 'Referencia al id del idioma en t040t_languages',
  `name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Nombre de la moneda en el idioma indicado. Ej: Afgani / Afghani',
  `status` int NOT NULL DEFAULT '1' COMMENT 'Estado del registro: 1 activo, 0 inactivo',
  `created_at` datetime(6) NOT NULL COMMENT 'Fecha y hora de creación del registro',
  `updated_at` datetime(6) NOT NULL COMMENT 'Fecha y hora de última actualización del registro',
  `created_by` int NOT NULL COMMENT 'Usuario que creó el registro',
  `updated_by` int NOT NULL COMMENT 'Usuario que realizó la última actualización del registro',
  PRIMARY KEY (`id`),
  UNIQUE KEY `UK_t042t_id_currency_id_language` (`id_currency`,`id_language`),
  KEY `IDX_t042t_id_currency` (`id_currency`),
  KEY `IDX_t042t_id_language` (`id_language`),
  CONSTRAINT `FK_t042t_id_currency_t041t` FOREIGN KEY (`id_currency`) REFERENCES `t041t_currencies` (`id`),
  CONSTRAINT `FK_t042t_id_language_t040t` FOREIGN KEY (`id_language`) REFERENCES `t040t_languages` (`id`),
  CONSTRAINT `CHK_NE_t042t_name` CHECK ((`name` <> _utf8mb4''))
) ENGINE=InnoDB AUTO_INCREMENT=512 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Nombres de monedas traducidos por idioma. Patrón i18n';
/*!40101 SET character_set_client = @saved_cs_client */;

